import{$ as e,A as t,B as n,V as r}from"./chunks/framework.qypF2UUz.js";var i=JSON.parse(`{"title":"内置插件","description":"","frontmatter":{"prev":{"text":"插件开发","link":"/plugins/introduction"},"next":{"text":"AI 对话","link":"/ai/chat"}},"headers":[],"relativePath":"plugins/builtin.md","filePath":"plugins/builtin.md","lastUpdated":1784193220000}`),a={name:`plugins/builtin.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r('<h1 id="内置插件" tabindex="-1">内置插件 <a class="header-anchor" href="#内置插件" aria-label="Permalink to “内置插件”">​</a></h1><h2 id="签到系统" tabindex="-1">签到系统 <a class="header-anchor" href="#签到系统" aria-label="Permalink to “签到系统”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>checkin</code></td><td style="text-align:left;">签到</td><td style="text-align:left;">每日签到，获取随机积分(10-100)和好感度(1-10)</td></tr><tr><td style="text-align:left;"><code>affection</code></td><td style="text-align:left;">好感度</td><td style="text-align:left;">查询当前好感度、积分、签到天数和等级进度</td></tr></tbody></table><p>好感度等级体系：</p><table tabindex="0"><thead><tr><th style="text-align:center;">好感度</th><th style="text-align:center;">等级</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td style="text-align:center;">冷漠</td></tr><tr><td style="text-align:center;">10</td><td style="text-align:center;">陌生</td></tr><tr><td style="text-align:center;">30</td><td style="text-align:center;">熟悉</td></tr><tr><td style="text-align:center;">50</td><td style="text-align:center;">友好</td></tr><tr><td style="text-align:center;">80</td><td style="text-align:center;">亲密</td></tr><tr><td style="text-align:center;">120</td><td style="text-align:center;">信赖</td></tr><tr><td style="text-align:center;">180</td><td style="text-align:center;">挚友</td></tr><tr><td style="text-align:center;">250</td><td style="text-align:center;">灵魂伴侣</td></tr></tbody></table><p>数据存储在 <code>data/checkin/{user_openid}.json</code>，每日排名通过 <code>_rank_cache.json</code> 缓存。</p><h2 id="生活工具" tabindex="-1">生活工具 <a class="header-anchor" href="#生活工具" aria-label="Permalink to “生活工具”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>weather</code></td><td style="text-align:left;">天气 &lt;城市&gt;</td><td style="text-align:left;">通过 wttr.in API 查询实时天气（温度、湿度、风速、日出日落）</td></tr><tr><td style="text-align:left;"><code>ping</code></td><td style="text-align:left;">ping &lt;域名/IP&gt;</td><td style="text-align:left;">执行 ping 检测，自动解析 IP 地理位置</td></tr><tr><td style="text-align:left;"><code>hitokoto</code></td><td style="text-align:left;">一言</td><td style="text-align:left;">获取随机一言句子</td></tr><tr><td style="text-align:left;"><code>domain_whois</code></td><td style="text-align:left;">whois &lt;域名&gt;</td><td style="text-align:left;">查询域名 Whois 信息</td></tr><tr><td style="text-align:left;"><code>httptest</code></td><td style="text-align:left;">http <code>&lt;URL&gt;</code></td><td style="text-align:left;">测试 HTTP 响应状态和延迟</td></tr></tbody></table><h3 id="天气" tabindex="-1">天气 <a class="header-anchor" href="#天气" aria-label="Permalink to “天气”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">天气</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 北京</span></span></code></pre></div><p>返回：当前温度、体感温度、温度范围、湿度、风速、天气描述、日出日落时间。</p><p>API: <a href="https://wttr.in/" target="_blank" rel="noreferrer">wttr.in</a></p><h3 id="ping" tabindex="-1">Ping <a class="header-anchor" href="#ping" aria-label="Permalink to “Ping”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.1.1.1</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> google.com</span></span></code></pre></div><p>返回：DNS 解析 IP、地理位置、ISP 信息、4 次 ping 延迟和平均值。</p><p>API: <a href="http://ip-api.com/" target="_blank" rel="noreferrer">ip-api.com</a></p><h2 id="娱乐工具" tabindex="-1">娱乐工具 <a class="header-anchor" href="#娱乐工具" aria-label="Permalink to “娱乐工具”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>acg_picture</code></td><td style="text-align:left;">图片</td><td style="text-align:left;">随机获取 ACG 图片</td></tr><tr><td style="text-align:left;"><code>qr_code</code></td><td style="text-align:left;">二维码 &lt;内容&gt;</td><td style="text-align:left;">生成二维码图片</td></tr><tr><td style="text-align:left;"><code>mc_status</code></td><td style="text-align:left;">mc &lt;服务器地址&gt;</td><td style="text-align:left;">查询 Minecraft 服务器状态</td></tr></tbody></table><h2 id="直播监控" tabindex="-1">直播监控 <a class="header-anchor" href="#直播监控" aria-label="Permalink to “直播监控”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kick</code></td><td style="text-align:left;">（后台）</td><td style="text-align:left;">监控踢人事件并记录</td></tr><tr><td style="text-align:left;"><code>kick_notify</code></td><td style="text-align:left;">—</td><td style="text-align:left;">踢人通知辅助</td></tr></tbody></table><h2 id="语音合成" tabindex="-1">语音合成 <a class="header-anchor" href="#语音合成" aria-label="Permalink to “语音合成”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>tts</code></td><td style="text-align:left;">—</td><td style="text-align:left;">AI 回复自动语音合成（后台调用）</td></tr></tbody></table><p>AI 对话回复后，如果内容长度在 1-200 字符之间，会自动尝试生成语音并发送。</p><h2 id="定时群发" tabindex="-1">定时群发 <a class="header-anchor" href="#定时群发" aria-label="Permalink to “定时群发”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">插件</th><th style="text-align:left;">触发</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>scheduled_send</code></td><td style="text-align:left;">群发 &lt;内容&gt;</td><td style="text-align:left;">管理员手动向所有通知群发消息</td></tr></tbody></table><p>后台任务：每天早上 <code>06:00</code>（北京时间）自动发送早间问候。</p><p>配置方式见 <code>config.json</code> 的 <code>scheduled_send</code> 字段。</p><h2 id="命令汇总" tabindex="-1">命令汇总 <a class="header-anchor" href="#命令汇总" aria-label="Permalink to “命令汇总”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>签到        - 每日签到获取积分和好感度</span></span>\n<span class="line"><span>好感度      - 查询好感度信息</span></span>\n<span class="line"><span>天气 `&lt;城市&gt;`  - 查询天气信息</span></span>\n<span class="line"><span>ping `&lt;地址&gt;`  - 对目标执行 ping</span></span>\n<span class="line"><span>一言        - 获取一言句子</span></span>\n<span class="line"><span>whois `&lt;域名&gt;` - 查询域名信息</span></span>\n<span class="line"><span>http `&lt;URL&gt;`  - 测试 HTTP 响应</span></span>\n<span class="line"><span>图片        - 随机 ACG 图片</span></span>\n<span class="line"><span>二维码 `&lt;内容&gt;` - 生成二维码</span></span>\n<span class="line"><span>mc `&lt;地址&gt;`   - 查询 MC 服务器状态</span></span>\n<span class="line"><span>群发 `&lt;内容&gt;`  - [管理员] 群发消息</span></span></code></pre></div>',29)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};